#include <bits/stdc++.h>
using namespace std;

int n, m, hx, hy;
long long f[25][25];

int main() {
    memset(f, -1, sizeof(f));
    cin >> n >> m >> hx >> hy;
    f[hx][hy] = 0;
    int d[2][8] = {
        {1, 2, 2, 1, -1, -2, -2, -1},
        {2, 1, -1, -2, -2, -1, 1, 2}
    };
    for (int i = 0; i < 8; i++) {
        int nx = hx + d[0][i];
        int ny = hy + d[1][i];
        if (nx <= n && ny <= m && nx >= 0 && ny >= 0)
            f[nx][ny] = 0;
    }
    int tmp = 1;
    for (int x = 0; x <= n; x++) {
        if (f[x][0] == 0) tmp = 0;
        f[x][0] = tmp;
    }
    tmp = 1;
    for (int y = 0; y <= m; y++) {
        if (f[0][y] == 0) tmp = 0;
        f[0][y] = tmp;
    }
    for (int y = 1; y <= m; y++) {
        for (int x = 1; x <= n; x++) {
            if (f[x][y] == -1) {
                f[x][y] = f[x - 1][y] + f[x][y - 1];
            }
        }
    }
    if (f[n][m] == -1) {
        cout << 0;
    }
    else {
        cout << f[n][m];
    }
    return 0;
}
